hop2_query:
SELECT ?airport ?airportLabel WHERE {
  # find the Leone Airways item by English label
  ?leone rdfs:label "Leone Airways"@en.

  # possible relations linking Leone Airways to an airline partner
  {
    ?leone wdt:P112 ?partner.      # founded by
  } UNION {
    ?leone wdt:P127 ?partner.      # owned by
  } UNION {
    ?leone wdt:P749 ?partner.      # parent organization
  } UNION {
    ?leone wdt:P137 ?partner.      # operator
  } UNION {
    ?leone wdt:P361 ?partner.      # part of
  }

  # partner's headquarters location is an airport
  ?partner wdt:P159 ?airport.
  ?airport wdt:P31/wdt:P279* wd:Q1248784.  # instance of (or subclass of) airport

  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}
LIMIT 10

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?type ?typeLabel WHERE {
  ?band rdfs:label "Isak N Jiyeon"@en.
  ?composition wdt:P175 ?band.
  ?composition wdt:P31 ?type.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}
